니다.
// Path Variable로 전달된 ID의 사용자 정보를 조회한다 suspend fun getMember(request: ServerRequest): ServerResponse { // Path Variable를 가져온다 val id = request.pathVariable(&#34;id&#34;) // ... } // Request Body로 전달된 데이터를 바탕으로 새 사용자를 만든다 suspend fun createMember(request: ServerRequest): ServerResponse { // Request Body를 클래스로 매핑한다 val form = request.bodyToMono(MemberCreateForm::class.java).awaitFirst() // ... } 다만 SpringFox처럼 API 문서를 자동 생성하는 도구는 대체로 리플렉션에 의존합니다. 그래서 Handler 내부에서 실제로 어떤 처리가 이루어지는지 추적하기가 어렵습니다. 다행히 이 문제를 Spring 쪽에서도 인식하고 있어서, springdoc-openapi를 사용하면 Functional Endpoint에서도 API 문서를 만들 수 있습니다. 하지만 이 경우에도 완전 자동은 아니고, 문서를 위한 메타데이터를 따로 지정해야 합니다. 그래서 Router나 Handler에 대해 다음처럼 어노테이션을 일일이 붙여야 합니다.
@Bean @RouterOperations( value = [ RouterOperation( path = &#34;/api/v1/members&#34;, beanClass = MemberHandler::class, beanMethod = &#34;listMember&#34;, method = [RequestMethod.GET], produces = [MediaType.APPLICATION_JSON_VALUE] ), RouterOperation( path = &#34;/api/v1/members/{id}&#34;, beanClass = MemberHandler::class, beanMethod = &#34;getMember&#34;, method = [RequestMethod.GET], produces = [MediaType.APPLICATION_JSON_VALUE] ), RouterOperation( path = &#34;/api/v1/members&#34;, beanClass = MemberHandler::class, beanMethod = &#34;createMember&#34;, method = [RequestMethod.POST], produces = [MediaType.APPLICATION_JSON_VALUE] ), RouterOperation( path = &#34;/api/v1/members/{id}&#34;, beanClass = MemberHandler::class, beanMethod = &#34;updateMember&#34;, method = [RequestMethod.PUT], produces = [MediaType.APPLICATION_JSON_VALUE] ), RouterOperation( path = &#34;/api/v1/members/{id}&#34;, beanClass = MemberHandler::class, beanMethod = &#34;deleteMember&#34;, method = [RequestMethod.DELETE], produces = [MediaType.APPLICATION_JSON_VALUE] ), ] ) fun routeMember() = coRouter { GET(&#34;/api/v1/members&#34;) { handler.listMember() } GET(&#34;/api/v1/members/{id}&#34;, handler::getMember) POST(&#34;/api/v1/members&#34;, handler::createMember) PUT(&#34;/api/v1/members/{id}&#34;, handler::updateMember) DELETE(&#34;/api/v1/members/{id}&#34;, handler::deleteMember) } 보시다시피 문서용 설정이 실제 코드보다 더 길어집니다. Functional Endpoint에서도 Swagger를 쓸 수는 있지만, MVC 패턴보다 불편한 건 사실입니다. 그래서 문서화가 중요하다면 아직은 Functional Endpoint를 신중하게 선택하는 편이 좋습니다.
마지막으로 여기서는 Spring WebFlux의 MVC 패턴과 Functional Endpoint를 코드 작성 방식, 성능, 문서화 관점에서 비교해 보았습니다. WebFlux가 나온 지는 꽤 됐지만, 아직은 MVC 패턴보다 손이 더 가는 부분이 분명히 있습니다. 제 경우에는 논블로킹과 함수형 스타일을 적극적으로 살리고 싶다면 Functional Endpoint가 더 어울린다고 보지만, 실제 프로젝트에서는 굳이 그 정도까지 갈 필요가 없는 경우도 많습니다. 특히 엔터프라이즈 애플리케이션이라면 더 그렇습니다. 결국 먼저 따져 봐야 할 것은 &ldquo;Functional Endpoint를 쓸까&quot;보다 &ldquo;애초에 WebFlux가 정말 필요한가&quot;일 수도 있습니다.
그렇다고 Functional Endpoint의 가능성이 작은 것은 아닙니다. Spring WebFlux 바깥에서도 이런 라우팅 방식은 이미 널리 쓰이고 있습니다. Express나 Gin 같은 프레임워크도 비슷한 모델을 제공하므로, 함수형 스타일에 익숙해지는 연습으로도 충분히 의미가 있습니다.

Java는 원래 절차형 언어에 가깝지만, 함수형 언어의 특징도 꽤 자연스럽게 받아들여 두 성격이 함께 공존하는 언어가 됐습니다. 저도 함수형 프로그래밍에 관심이 있어서 Java에서도 Stream이나 Lambda를 자주 쓰고, Kotlin이나 Spring WebFlux로도 이것저것 실험해 보고 있습니다. 다만 Java 8 이후로 계속 따라다닌 질문이 하나 있습니다. Stream이 과연 모든 for 루프를 대체할 수 있느냐는 것입니다. 보통은 성능, 가독성, 디버깅 난이도 때문에 전통적인 루프를 완전히 버리지는 못한다고 말합니다. 내부 처리가 조금 더 복잡하고, 예외가 났을 때 원인을 좁히기 어렵고, method chaining이나 lambda에 익숙하지 않은 사람도 많기 때문입니다. 그래서 저도 평소에는 List는 ArrayList, 루프는 확장 for문, 요소를 가공하거나 새 인스턴스를 만들어야 할 때만 Stream을 쓰는 식으로 지내 왔습니다. 그런데 문득 이 기준이 정말 맞는지 다시 확인해 보고 싶었습니다. Java도 이미 16까지 올라왔고, 함수형 스타일을 더 적극적으로 써도 되는 시점인지, 아니면 예전 상식이 아직도 유효한지 직접 보고 싶었습니다. 그래서 이번에는 가벼운 벤치마크를 곁들여 여러 루프 방식을 비교해 보았습니다. 사실은 벤치마크를 돌려 보고 싶었던 마음이 더 컸습니다.
루프 방법 이번 글에서는 Collection과 배열을 다루는 네 가지 루프 방식을 중심으로 이야기해 보겠습니다. 많은 경우 아래 같은 기준으로 루프를 선택하지 않을까 생각합니다.
종류 사용하는 상황 For 인덱스가 필요할 때 확장 For 다른 방법을 쓸 필요가 없을 때 Iterator 기본적으로 잘 쓰지 않음 forEach() 기본적으로 잘 쓰지 않음 이 기준의 중심에는 결국 성능이 있습니다. 가독성 같은 다른 요소도 물론 중요하지만, 성능이 우선되는 경우가 가장 많습니다. 다른 요소는 튜닝이 어렵거나 아예 바꾸기 힘든 경우도 많고, 성능은 리팩토링으로 눈에 보이게 개선할 수 있는 대표적인 항목이기 때문입니다. 같은 처리를 한다면 더 빠른 쪽이 좋은 건 당연합니다.
제가 루프를 처음 배울 때는 전통적인 For문과 While문이 기본이었고, 나중에는 Collection이나 배열을 돌릴 때는 확장 For문을 쓰는 게 좋다는 식으로 배웠습니다. 그때의 근거도 &ldquo;For와 확장 For는 성능 차이가 크지 않고, 확장 For는 요소 수만큼 자연스럽게 돈다&quot;는 설명이었습니다. 꽤 납득이 가는 이야기였고, 저도 그 말을 믿고 계속 확장 For문을 써 왔습니다.
하지만 실제로 어떤 차이가 있는지는 별도로 검증해 본 적이 많지 않았습니다. 검색해 보면 확장 For문은 기존 루프를 더 쓰기 쉽게 만든 형태라거나, Iterator의 문법적 설탕이라는 설명이 많지만, 정작 어떤 방식이 가장 빠른지는 직접 봐야 한다고 생각했습니다. Stream과 forEach()도 마찬가지입니다. Java에 도입된 뒤에도 성능이 느리다는 평이 많고, 굳이 써야 할 이유를 모르겠다는 의견이나 어렵다는 의견도 있습니다. Java 8 시절부터 성능 비교가 많이 이루어졌고, 적어도 성능 면에서는 기존 방식이 유리하다는 결론이 자주 나왔습니다. Java 버전이 16까지 올라온 지금도 그 인식은 크게 바뀌지 않았습니다.
하지만 &ldquo;누군가 그렇게 말했으니 그렇다&quot;고 믿는 건 좋은 태도는 아닙니다. Java는 계속 발전하고 있고, JVM이나 컴파일러 차원에서 보이지 않는 개선이 있었을 수도 있습니다. 함수형 스타일에 익숙한지 아닌지는 개인 차이지만, 성능까지 좋아졌다면 굳이 새 방식을 피할 이유도 없습니다. 게다가 정말로 확장 For문이 모든 경우에 최선인지도 직접 확인해 볼 필요가 있습니다.
그래서 우선 비교 대상으로 삼을 네 가지 루프 방식을 소개하고, 이어서 벤치마크 결과를 살펴보겠습니다.
For 문 우선은 전통적인 형태의 For문입니다. 일부에서는 c-style이라고도 부릅니다. 가장 기본적인 방식이라 익숙하지만, 한편으로는 다소 낡은 느낌도 있습니다. 최근의 이른바 모던한 언어에서는 이런 형태의 루프를 아예 쓸 수 없는 경우도 있습니다. 기본 형태는 다음과 같습니다.
for (int i = 0; i &lt; list.size(); i++) { System.out.println(list.get(i)); } 마이크로 최적화 차원에서 루프 대상 Collection이나 배열의 길이를 미리 변수에 담아 두는 경우도 있습니다. 이렇게 하면 매 반복마다 크기를 다시 확인하지 않아도 되기 때문에 조금이나마 유리하다고들 합니다. 물론 이 정도는 컴파일러가 최적화해 줄 수도 있습니다.
int size = list.size(); for (int i = 0; i &lt; size; i++) { list.get(i); } 전통적인 for문의 장점은 인덱스를 기준으로 제어할 수 있다는 점입니다. 그래서 인덱스가 꼭 필요한 상황에서는 여전히 가장 직접적인 선택지입니다. 예를 들면 아래와 같습니다.
// 짝수 인덱스만 처리하고 싶을 때 for (int i = 0; i &lt; list.size(); i += 2) { System.out.println(list.get(i)); } // 조건과 일치하는 요소의 인덱스를 알고 싶을 때 for (int i = 0; i &lt; list.size(); i++) { if (list.get(i).length() == 10) { System.out.println(i); } } // 앞뒤 요소와 비교하고 싶을 때 for (int i = 1; i &lt; list.size(); i += 2) { System.out.println(&#34;인덱스 &#34; + (i - 1) + &#34;의 길이: &#34; + list.get(i - 1).length() + &#34;, 인덱스 &#34; + i + &#34;의 길이: &#34; + list.get(i).length()); } 다만 인덱스를 직접 다루는 만큼 범위를 잘못 잡기 쉽다는 문제가 있습니다. i - 1 같은 접근을 잘못 쓰면 바로 예외로 이어질 수 있고, 숫자 상수가 많아지면 매직 넘버 때문에 가독성도 떨어집니다. 그래서 인덱스 기반 처리가 꼭 필요할 때만 조심해서 쓰는 편이 낫습니다.
확장 For 문 이른바 for-each문입니다. Collection이나 배열의 모든 요소를 순서대로 처리할 때는 가장 읽기 쉽고 안전한 방식에 가깝습니다.
for (String element : list) { System.out.println(element); } 최근에는 Java뿐 아니라 다른 언어에서도 이런 방식이 기본에 가깝습니다. 인덱스를 직접 움직이는 것보다, &ldquo;이 컬렉션의 각 요소를 순회한다&quot;는 의도가 더 분명하게 드러나기 때문입니다. 물론 단점도 있습니다. 확장 for문 안에서는 인덱스를 바로 쓸 수 없습니다. 꼭 인덱스가 필요하다면 루프 밖에서 별도 정수를 증가시키거나, indexOf(), Collections.binarySearch() 같은 방법을 고려할 수 있습니다.
// 상수를 이용하는 방법 int i = 0; for (String element : list) { System.out.println(element + &#34;의 인덱스: &#34; + i); i++; } // indexOf()를 사용하는 경우 for (String element : list) { System.out.println(element + &#34;의 인덱스: &#34; + list.indexOf(element)); } // Collections.binarySearch()를 사용하는 경우 for (String element : list) { System.out.println(element + &#34;의 인덱스: &#34; + Collections.binarySearch(values, value)); } 다만 루프 안에서 indexOf()를 매번 호출하는 것은 좋은 선택이 아닙니다. 결국 컬렉션 내부를 다시 순회하게 되므로 사실상 이중 루프가 됩니다. 인덱스가 정말 필요하다면 차라리 카운터 변수를 두거나 전통적인 for문을 쓰는 편이 낫습니다.
// ArrayList.indexOf() public int indexOf(Object o) { return indexOfRange(o, 0, size); } int indexOfRange(Object o, int start, int end) { Object[] es = elementData; if (o == null) { for (int i = start; i &lt; end; i++) { if (es[i] == null) { return i; } } } else { for (int i = start; i &lt; end; i++) { if (o.equals(es[i])) { return i; } } } return -1; } Collections의 binarySearch()을 이용하는 경우도, 결국 루프하면서 인덱스를 찾는 것은 변하지 않으므로 주의를. 다음은 그 구현입니다.
// Collections.binarySearch() public static &lt;T&gt; int binarySearch(List&lt;? extends Comparable&lt;? super T&gt;&gt; list, T key) { if (list instanceof RandomAccess || list.size()&lt;BINARYSEARCH_THRESHOLD) return Collections.indexedBinarySearch(list, key); else return Collections.iteratorBinarySearch(list, key); } private static &lt;T&gt; int indexedBinarySearch(List&lt;? extends Comparable&lt;? super T&gt;&gt; list, T key) { int low = 0; int high = list.size()-1; while (low &lt;= high) { int mid = (low + high) &gt;&gt;&gt; 1; Comparable&lt;? super T&gt; midVal = list.get(mid); int cmp = midVal.compareTo(key); if (cmp &lt; 0) low = mid + 1; else if (cmp &gt; 0) high = mid - 1; else return mid; // key found } return -(low + 1); // key not found } private static &lt;T&gt; int iteratorBinarySearch(List&lt;? extends Comparable&lt;? super T&gt;&gt; list, T key) { int low = 0; int high = list.size()-1; ListIterator&lt;? extends Comparable&lt;? super T&gt;&gt; i = list.listIterator(); while (low &lt;= high) { int mid = (low + high) &gt;&gt;&gt; 1; Comparable&lt;? super T&gt; midVal = get(i, mid); int cmp = midVal.compareTo(key); if (cmp &lt; 0) low = mid + 1; else if (cmp &gt; 0) high = mid - 1; else return mid; // key found } return -(low + 1); // key not found } Iterator Iterator는 개인적으로도 그다지 손이 가지 않는 방식입니다. 컬렉션 자체보다 Iterator가 전면에 나오기 때문에, 코드에서 &ldquo;무엇을 순회하는가&quot;보다 &ldquo;어떻게 순회하는가&quot;가 더 두드러져 보이는 느낌이 있습니다. 확장 for문보다 의도가 덜 직접적으로 보인다는 뜻입니다. 어쨌든 Iterator는 for와 while 둘 다로 사용할 수 있습니다.
// For를 사용하는 경우 for (Iterator iterator = values.iterator(); iterator.hasNext(); ) { System.out.println(iterator.next()); } // While를 사용하는 경우 Iterator iterator = values.iterator(); while (iterator.hasNext()) { System.out.println(iterator.next()); } Iterator의 문제는 사용법이 직관적이지 않을 때가 있다는 점입니다. 예를 들어 아래 코드는 getFoo()와 getBar()가 같은 객체에 대해 호출되는 것처럼 보이기 쉽지만, 실제로는 next()가 두 번 호출됩니다.
for (Iterator iterator = list.iterator(); iterator.hasNext(); ) { System.out.println(iterator.next().getFoo()); System.out.println(iterator.next().getBar()); // 주의! } 흥미롭게도 확장 for문의 바이트코드는 결국 Iterator를 사용하는 형태로 바뀝니다. 그런 의미에서 확장 for문은 Iterator를 더 안전하고 읽기 쉽게 감싼 문법이라고 볼 수 있습니다.
forEach() forEach()는 비교적 현대적인 스타일의 반복 방식입니다. 확장 for문과 크게 다르지는 않지만, 람다나 메서드 참조를 자연스럽게 쓸 수 있다는 장점이 있습니다. 처리 범위가 블록 안에 깔끔하게 묶인다는 점도 나쁘지 않습니다.
list.forEach(System.out::println) 구현도 기본적으로는 확장 for문 안에서 lambda를 실행하는 단순한 형태입니다. 그래서 직관적으로는 확장 for문보다 조금 불리할 수 있어 보입니다. 아래는 Iterable 쪽 구현입니다.
// Iterable의 forEach() default void forEach(Consumer&lt;? super T&gt; action) { Objects.requireNonNull(action); for (T t : this) { action.accept(t); } } 다만 ArrayList는 구현이 꽤 다릅니다. 그래서 성능도 꽤 달라질 가능성이 있습니다. 아래는 그 구현입니다.
// ArrayList의 forEach() public void forEach(Consumer&lt;? super E&gt; action) { Objects.requireNonNull(action); final int expectedModCount = modCount; final Object[] es = elementData; final int size = this.size; for (int i = 0; modCount == expectedModCount &amp;&amp; i &lt; size; i++) action.accept(elementAt(es, i)); if (modCount != expectedModCount) throw new ConcurrentModificationException(); } static &lt;E&gt; E elementAt(Object[] es, int index) { return (E) es[index]; } 벤치 마크로 확인해 보면 이번에도 JMH로 간단한 벤치마크를 만들어 봤습니다. 처음에는 static final 필드로 두면 모든 벤치마크가 같은 객체를 공유할 거라고 생각했는데, 실제로는 그렇지 않았습니다. 그래서 이번에는 @Setup을 써서 필드를 명시적으로 초기화했습니다.
@State(Scope.Thread) public class LoopTest { private List&lt;String&gt; values; @Setup public void init() { final DecimalFormat format = new DecimalFormat(&#34;0000000&#34;); values = IntStream.rangeClosed(0, 9999999).mapToObj(format::format).collect(Collectors.toList()); } @Benchmark public void indexLoop(Blackhole bh) { final int length = values.size(); for (int i = 0; i &lt; length; i++) { bh.consume(values.get(i)); } } @Benchmark public void iteratorLoopFor(Blackhole bh) { for (Iterator iterator = values.iterator(); iterator.hasNext(); ) { bh.consume(iterator.next()); } } @Benchmark public void iteratorLoopWhile(Blackhole bh) { final Iterator iterator = values.iterator(); while (iterator.hasNext()) { bh.consume(iterator.next()); } } @Benchmark public void extendedLoop(Blackhole bh) { for (String value : values) { bh.consume(value); } } @Benchmark public void forEachLoop(Blackhole bh) { values.forEach(bh::consume); } } 그리고 벤치마크 결과는 다음과 같습니다.
Benchmark Mode Cnt Score Error Units LoopTest.indexLoop thrpt 25 27.737 ± 0.475 ops/s LoopTest.iteratorLoopFor thrpt 25 26.968 ± 0.556 ops/s LoopTest.iteratorLoopWhile thrpt 25 27.250 ± 0.557 ops/s LoopTest.extendedLoop thrpt 25 13.186 ± 0.152 ops/s LoopTest.forEachLoop thrpt 25 12.479 ± 0.104 ops/s 역시 네 가지 루프는 서로 다른 결과를 보여 줍니다. 적어도 여기서는 전통적인 For문이 성능 면에서 가장 유리해 보입니다. &ldquo;확장 For문을 써도 성능 차이는 크지 않다&quot;는 말이 다시 보일 정도였습니다.
그렇다고 해서 바로 &ldquo;성능이 좋은 쪽만 고르면 된다&quot;는 결론을 내려도 될까요?
생각하고 싶은 것 결과가 같다면 더 빠른 쪽을 고르고 싶어지는 건 자연스럽습니다. 특히 업무 시스템에서는 성능이 곧 비용과 연결되기도 합니다. 하지만 실제 애플리케이션 개발에서 고려할 요소는 성능만이 아닙니다. 극단적으로 성능만 따진다면 웹 애플리케이션도 C나 C++로 작성해야겠지만, 그러면 생산성과 유지보수성이 크게 떨어질 수 있습니다. 읽기 어려운 고성능 코드가 결국 더 큰 비용을 부르는 경우도 흔합니다. 그래서 루프를 고를 때도 성능 외에 가독성, 오류 발생 가능성, 처리 대상의 특성까지 함께 봐야 합니다. 이제는 그런 관점에서 네 가지 루프를 다시 비교해 보겠습니다.
가독성과 오류 발생 가능성 측면에서 생각 확장 for문이나 forEach()는 기본적으로 요소 자체에 집중하게 만듭니다. 반대로 전통적인 for문이나 Iterator는 인덱스나 현재 위치를 더 직접적으로 제어할 수 있습니다. 겉보기에는 조건에 맞는 요소만 골라 처리할 때 후자가 더 강력해 보일 수 있습니다. 하지만 관점을 바꾸면, 원본 객체를 직접 수정할 수 있다는 점은 오히려 단점이 되기도 합니다. 사이드 이펙트를 줄이려면 원본을 바꾸는 대신 조건에 맞는 요소만 담은 새 컬렉션을 만드는 편이 더 안전할 때가 많습니다. 이런 의도를 코드로 드러내기에는 확장 for문이나 Stream 쪽이 더 읽기 쉽습니다. 예를 들면 다음과 같습니다.
// 원본 리스트가 변해 버리는 방식 public void filterFor(List&lt;String&gt; list) { for (int i = 0; i &lt; list.size(); i++) { if (list.get(i).length() &gt; 10) { list.remove(i); } } } // 원본 리스트에 영향이 없는 방식 - For문 public List&lt;String&gt; filterFor(List&lt;String&gt; list) { List&lt;String&gt; result = new ArrayList&lt;&gt;(); for (int i = 0; i &lt; list.size(); i++) { String element = list.get(i); if (element.length() &lt;= 10) { result.add(element); } } return result; } // 원본 리스트에 영향이 없는 방식 - 확장 For문 public List&lt;String&gt; filterForEach(List&lt;String&gt; list) { List&lt;String&gt; result = new ArrayList&lt;&gt;(); for (String element : list) { if (element.length() &lt;= 10) { result.add(element); } } return result; } // 원본 리스트에 영향이 없는 방식 - Stream.forEach() public List&lt;String&gt; filterStream(List&lt;String&gt; list) { return list.stream().filter(element -&gt; element.length() &lt;= 10).collect(Collectors.toList()); } 좋은 코드는 결국 짧기만 한 코드가 아니라, 읽는 사람이 쉽게 이해하고 실수하기 어려운 코드라고 생각합니다. 그런 기준에서 보면 전통적인 for문과 Iterator는 꼭 필요한 경우에만 쓰고, 기본값으로는 더 안전한 방식을 선택하는 편이 낫습니다.
처리 능력 측면에서 생각 처리 능력이라는 관점은 결국 성능과도 이어집니다. 다만 여기서 핵심은 &ldquo;어떤 컬렉션 구현이 들어와도 크게 흔들리지 않는 방식이 무엇인가&quot;입니다. 예를 들어 List를 인자로 받아 루프를 도는 메소드를 만든다고 해 봅시다. 이때 어떤 루프를 고를지는, 그 List가 실제로 어떤 구현 클래스인지 모른다는 사실까지 함께 고려해야 합니다. List는 인터페이스이기 때문에, 실제로는 ArrayList일 수도 있고 LinkedList일 수도 있습니다. 더 나아가 다른 구현이 들어올 가능성도 있습니다. 인터페이스를 기준으로 코드를 작성한다는 것은, 결과 자체는 구현 클래스가 달라도 유지된다는 뜻입니다. 하지만 성능까지 같다는 뜻은 아닙니다. List 구현이 여러 개 존재하는 이유 자체가 사용 목적에 따라 서로 다른 특성을 가지기 때문입니다. 가장 흔한 구현은 ArrayList지만, 경우에 따라서는 LinkedList 같은 다른 구현이 들어올 수도 있습니다. 그렇다면 ArrayList에서 빠른 방식이 LinkedList에서도 그대로 빠를 것이라고 가정하는 건 위험합니다. 위에서 실시한 벤치마크만 보고 성능은 절대 이것이 유리하다고 말할 수 없는 이유가 여기에 있습니다. 왜냐하면 테스트와 같은 데이터를 Collectors.toList()을 사용하여 List로 작성하고 있습니다.
public static &lt;T&gt; Collector&lt;T, ?, List&lt;T&gt;&gt; toList() { return new CollectorImpl&lt;&gt;((Supplier&lt;List&lt;T&gt;&gt;) ArrayList::new, List::add, (left, right) -&gt; { left.addAll(right); return left; }, CH_ID); } 그래서 다른 구현 클래스에서도 벤치마크를 해 보기로 했습니다. 물론 모든 List 구현을 다 테스트하는 것은 현실적이지 않습니다. 여기서는 ArrayList와 성격이 확실히 다른 반례 하나면 충분하다고 보고 LinkedList를 골랐습니다. 다행히 Collectors.toCollection()을 사용하면 컬렉션 구현을 쉽게 바꿀 수 있습니다. 그래서 기존 벤치마크 코드에서 아래 한 줄만 바꾸면 됩니다.
// LinkedList의 경우 values = IntStream.rangeClosed(0, 9999999).mapToObj(format::format).collect(Collectors.toCollection(LinkedList::new)); LinkedList의 경우 요소 수가 증가하면 성능이 급격히 떨어지는 경향이 있습니다. 그래서 ArrayList 때보다 요소수는 2자리 정도 줄여 벤치마크를 실시했습니다. 결과는 다음과 같습니다.
Benchmark Mode Cnt Score Error Units LoopTest.indexLoop thrpt 25 0.084 ± 0.005 ops/s LoopTest.iteratorLoopFor thrpt 25 854.459 ± 36.771 ops/s LoopTest.iteratorLoopWhile thrpt 25 839.233 ± 18.142 ops/s LoopTest.extendedLoop thrpt 25 659.999 ± 47.702 ops/s LoopTest.forEachLoop thrpt 25 780.463 ± 78.591 ops/s 결과는 ArrayList 때와 거의 정반대였습니다. 특히 인덱스 기반 루프는 사실상 쓰기 어려울 정도로 느렸고, forEach()가 확장 for문보다 좋은 결과를 보인 것도 꽤 의외였습니다. 이 수치를 절대 기준으로 삼을 수는 없지만, 적어도 &ldquo;ArrayList에서 빠르니까 모든 List에서도 빠를 것&quot;이라고 단정하는 건 위험하다는 점은 분명합니다. 결국 중요한 것은 특정 구현 하나에서 가장 빠른 방식이 아니라, 다양한 구현에서 평균적으로 무난한 방식을 고르는 일입니다. 그런 기준에서는 확장 for문이 꽤 안정적인 선택처럼 보입니다.
마지막으로 모든 상황에서 완벽한 코드를 처음부터 쓰기는 어렵습니다. 그래서 예전에 작성한 코드를 다시 읽어 보면, 그때는 몰랐던 중복이나 불필요한 객체 생성이 눈에 들어오는 경우가 많습니다. 저도 가끔 옛 코드를 보면 꽤 놀랍니다. 그래서 이렇게 기본적인 주제라도 한 번 다시 검토해 보는 일은 의미가 있습니다. 루프는 너무 익숙해서 별 고민 없이 쓰기 쉽지만, 막상 비교해 보면 선택 기준이 생각보다 단순하지 않습니다. 그런 점을 직접 확인해 보는 데 벤치마크는 꽤 재미있고 유용한 도구였습니다. 루프처럼 익숙한 주제일수록, 한 번쯤 이렇게 다시 확인해 보는 과정이 꽤 도움이 됩니다.

어노테이션은 일반 Java에서도 쓸 수 있고, 여러 라이브러리와 프레임워크에서 적극적으로 활용합니다. 그중에서도 어노테이션을 가장 잘 쓰는 곳은 Spring이라고 생각합니다. DI를 하든 클래스의 역할을 구분하든, 대부분을 어노테이션으로 간단하게 정의할 수 있게 해 주기 때문입니다. 그래서 Spring으로 Web 애플리케이션을 만들 때는 어떤 어노테이션이 있는지 익혀 두는 것이 중요합니다.
이 이야기를 꺼낸 이유는, 이전 글에서 Service를 바꾸는 방법을 설명한 뒤 다른 방법이 있는지 찾아보다가, Spring에서는 조건에 따라 Bean이나 Configuration을 등록하는 어노테이션도 있다는 걸 알게 됐기 때문입니다.
또 조건에 따라 쓸 수 있는 어노테이션이 여러 가지라서, 이번에는 그중 자주 보이는 것들을 정리해 보려고 합니다. 이런 어노테이션들은 Spring Boot의 auto-configuration 계열과 맞닿아 있습니다. 이미 많은 설정이 자동화되어 있지만, 그 자동 설정을 더 세밀하게 다룰 수 있도록 도와주는 도구라고 보면 됩니다.
참고로, 여기서 소개하는 것들을 전부 직접 실험해 본 것은 아니고, 일단 정리 차원에서 소개하는 글입니다.
조건에 따라 DI하기 이전 글에서 소개한 코드를 다시 보겠습니다. application.yml에 적힌 값에 따라 어떤 Repository를 DI할지 결정하는 방식이었습니다.
@Configuration public class SomeServiceConfig { // YAML에 설정한 값을 읽는다 @Value(&#34;${settings.TestMode:false}&#34;) private boolean testMode; // YAML 설정에 따라 어떤 Impl을 쓸지 결정해 Bean 등록 @Bean public SomeService someService(SomeRepository repository, SomeTestRepository testRepository) { return this.testMode ? new SomeTestSerivce(testRepository) : new SomeServiceImple(repository); } } 이와 비슷한 동작을 Spring의 조건부 어노테이션으로 구현하면 이렇게 바뀝니다.
@Configuration public class SomeServiceConfig { // 운영용 서비스 클래스 @Bean @ConditionalOnProperty(value = &#34;settings.Testmode&#34;, havingValue = &#34;false&#34;) public SomeService someService(SomeRepository repository) { return new SomeServiceImple(repository); } // 테스트용 서비스 클래스 @Bean @ConditionalOnProperty(value = &#34;settings.Testmode&#34;, havingValue = &#34;true&#34;) public SomeService someTestService(SomeTestRepository testRepository) { return new SomeTestService(); } } @ConditionalOnProperty를 쓰면 특정 조건에 따라 메서드가 실행되도록 만들 수 있습니다. 굳이 분기문을 직접 쓰거나 커스텀 @Value 처리를 만들지 않아도 되니 훨씬 깔끔합니다.
이 어노테이션은 @Bean뿐 아니라 다른 Spring 클래스 어노테이션인 @Configuration, @Component, @Service, @Repository, @Controller에도 쓸 수 있어서 활용 범위가 넓습니다.
Spring Boot의 org.springframework.boot.autoconfigure.condition 패키지에는 이런 식의 @Conditional... 어노테이션이 더 있습니다. 하나씩 간단히 보겠습니다.
미리 정의된 Conditional 어노테이션 @ConditionalOnProperty application.yml이나 시스템 프로퍼티에 지정한 값이 있을 때 실행되는 어노테이션입니다. Spring Boot에서 가장 자주 쓰이는 조건부 어노테이션 중 하나입니다. 괄호 안에서 프로퍼티 이름과 기대값을 지정하고, 값이 없을 때도 동작하게 할지 정할 수 있습니다.
아래 코드는 use.testmode가 존재하고 값이 true일 때 실행되는 Configuration 예시입니다. matchIfMissing를 true로 두면 해당 프로퍼티가 없어도 실행됩니다.
@Configuration @ConditionalOnProperty(value = &#34;use.testmode&#34;, havingValue = &#34;true&#34;, matchIfMissing = true) public class TestConfig { // 테스트 모드에서 사용할 Configuration } @ConditionalOnExpression 프로퍼티를 표현식으로 판단해 실행하는 어노테이션입니다. 괄호 안에 조건식을 넣으면 됩니다. 이때 조건식은 @Value 등에서도 쓰는 SpEL을 사용합니다. 아래 예시는 use.testmode와 use.submode가 모두 true일 때 실행됩니다.
@Configuration @ConditionalOnExpression(&#34;${use.testmode:true} and ${use.submode:true}&#34;) public class TestSubConfig { // 테스트 모드와 서브 모드가 모두 true일 때 사용할 Configuration } @ConditionalOnBean 지정한 Bean이 존재할 때 실행되는 어노테이션입니다. 괄호 안에 Bean으로 등록됐는지 확인할 클래스를 넣으면 됩니다. 예를 들어 어떤 Bean이 등록됐을 때 그에 맞는 보조 설정도 함께 넣고 싶을 때 사용할 수 있습니다.
@Configuration @ConditionalOnBean(TestRepository.class) public class TestBeanConfig { // 테스트용 Bean이 등록됐을 때 사용할 Configuration } @ConditionalOnMissingBean @ConditionalOnBean의 반대입니다. 지정한 Bean이 없을 때 실행됩니다.
@Configuration public class AlternativeConfigutration { @Bean @ConditionalOnMissingBean public Repository testRepository() { return new TestRepository(); } } @ConditionalOnResource 리소스 파일이 존재할 때 실행되는 어노테이션입니다. 예를 들어 Logback을 쓸 때 xml 파일이 있으면 그 설정도 함께 활성화하고 싶을 때 사용할 수 있습니다.
@Configuration @ConditionalOnResource(resources = &#34;/logback.xml&#34;) public class LogbackConfig { // resources 폴더에 logback.xml이 있을 때 사용하는 Configuration } @ConditionalOnClass 지정한 클래스가 존재할 때 실행됩니다. @ConditionalOnBean과 비슷하지만, Bean이어야 할 필요는 없습니다. 외부 라이브러리가 클래스패스에 들어왔는지 확인할 때 유용합니다.
@Configuration @ConditionalOnClass(name = &#34;com.custom.library.module.SomeClass&#34;) public class CustomLibraryConfig { // 커스텀 라이브러리의 SomeClass가 있을 때 사용하는 Configuration } @ConditionalOnMissingClass @ConditionalOnClass의 반대입니다. 지정한 클래스가 없을 때 실행됩니다.
@Configuration @ConditionalOnMissingClass(name = &#34;com.custom.library.module.SomeClass&#34;) public class NoCustomLibraryConfig { // 커스텀 라이브러리의 SomeClass가 없을 때 사용하는 Configuration } @ConditionalOnJava 애플리케이션이 어떤 Java 버전에서 실행되는지에 따라 동작을 바꾸는 어노테이션입니다. 버전별로 API가 달라질 수 있으니, 여러 환경을 지원해야 할 때 유용합니다.
@Configuration @ConditionalOnJava(JavaVersion.EIGHT) public class JavaEightConfig { // Java 1.8에서 사용하는 Configuration } 커스텀 Condition Condition 인터페이스를 직접 구현하면 커스텀 조건도 만들 수 있습니다. 예를 들어 애플리케이션이 Linux에서 실행될 때만 동작하도록 만들 수 있습니다.
핵심은 matches() 메서드가 boolean을 반환하도록 구현하는 것입니다.
class OnUnixCondition implements Condition { // OS가 Linux인지 판별하는 Condition @Override public boolean matches(ConditionContext context, AnnotatedTypeMetadata metadata) { return SystemUtils.IS_OS_LINUX; } } 이렇게 만든 Condition은 @Conditional에 붙여서 사용합니다.
@Configuration public class OsConfig { // Linux일 때 Bean 등록 @Bean @Conditional(OnUnixCondition.class) public UnixBean unixBean() { return new UnixBean(); } } AnyNestedCondition을 상속하면 더 복잡한 조건도 만들 수 있습니다. 앞의 OnUnixCondition 외에 Windows 여부를 판별하는 OnWindowsCondition도 있다고 해 봅시다. 이런 경우는 아래처럼 만들 수 있습니다.
public class OnWindowsOrUnixCondition extends AnyNestedCondition { OnWindowsOrUnixCondition() { super(ConfigurationPhase.REGISTER_BEAN); } @Conditional(OnWindowsCondition.class) public static class OnWindows { // Windows일 때 } @Conditional(OnUnixCondition.class) public static class OnUnix { // Linux일 때 } } 이렇게 만든 Condition도 같은 방식으로 @Conditional에 넣어 사용합니다.
@Configuration public class OsConfig { // Windows 또는 Linux일 때 등록되는 Bean @Bean @Conditional(OnWindowsOrUnixCondition.class) public WindowsOrUnixBean windowsOrUnixBean() { return new WindowsOrUnixBean(); } } 마지막으로 여기서 소개한 것 말고도 org.springframework.boot.autoconfigure.condition 패키지 아래에는 여러 조건부 클래스가 더 있습니다. 예를 들어 Web 애플리케이션인지, 클라우드 플랫폼인지에 따라 동작을 바꾸는 어노테이션도 있고, 앞으로도 여러 조건이 더 추가될 수 있습니다.
이런 Conditional 계열 어노테이션은 Spring Boot의 Auto Configuration에서도 쓰이는 것들입니다. 직접 프로퍼티를 읽고 if를 쓰는 것보다 훨씬 안정적이고, 조건별로 어노테이션이 따로 존재하니 재사용성도 좋습니다. 커스텀 Condition까지 만들 수 있으니 꽤 유용합니다.
직접 프로퍼티를 읽고 if로 분기하는 방식도 물론 가능합니다. 하지만 Spring이 이미 제공하는 조건부 어노테이션을 활용하면 코드가 더 분명해지고, 설정 의도도 훨씬 잘 드러납니다. 이런 도구를 알고 있느냐가 결국 Spring 코드를 얼마나 깔끔하게 유지할 수 있는지와도 연결된다고 느꼈습니다.

Spring에서 비즈니스 로직을 작성할 때는 보통 Service 클래스를 만듭니다. Service는 핵심 처리를 담고 있어서 개발과 테스트 모두에서 중요한 역할을 합니다. 그런데 실제로 개발을 하다 보면, 구현은 했지만 아직 돌릴 수 없는 상황이 생깁니다. 예를 들어 환경이 아직 준비되지 않았거나, 다른 클래스에 의존하는 설계인데 그 클래스가 아직 없을 수도 있습니다. 이런 경우에는 실제 처리를 하지 않고 항상 같은 값을 돌려주는 대체 구현을 두기도 합니다.
이럴 때 미리 여러 Service 구현 클래스를 만들어 두고, 외부 설정 파일인 application.yml에서 개발 모드인지 테스트 모드인지에 따라 어떤 구현을 쓸지 선택할 수 있으면 편리합니다. 실제로 Service는 인터페이스와 구현 클래스(Impl)를 분리하는 경우가 많기 때문에, 여러 Impl 클래스를 만들어 상황에 따라 다른 Bean으로 등록하는 것도 가능합니다.
이번 글에서는 YAML 설정을 읽어서 어떤 상황에서 어떤 ServiceImpl을 Bean으로 등록할지 결정하는 방법을 정리해 보겠습니다.
Service의 기본 구조 일반적인 Service 구조는 아래와 같습니다. 인터페이스를 만들고, 이를 구현한 클래스를 작성하는 방식입니다. 중간에 DB 같은 외부 시스템과 연동하는 클래스를 DI해서 쓰는 경우가 많습니다.
public interface SomeService { public void doSomething(); } @Service public class SomeServiceImpl implements SomeService { private SomeRepository repository; @Autowired public SomeServiceImpl(SomeRepository repository) { this.repository = repository; } @Override public void doSomething() { // ... } } 테스트용으로 별도 구현 클래스를 하나 더 만든다고 해 봅시다.
@Service public class SomeTestServiceImpl implements SomeService { private SomeTestRepository testRepository; @Autowired public SomeServiceImpl(SomeTestRepository testRepository) { this.testRepository = testRepository; } @Override public void doSomething() { // ... } } 이렇게 되면 애플리케이션을 시작할 때 Spring이 &ldquo;이 인터페이스의 구현체를 어느 걸 써야 하지?&rdquo; 하고 헷갈리게 됩니다. 하나의 인터페이스에 두 개의 구현 클래스가 있고, 둘 다 Bean으로 등록하려고 하기 때문입니다.
어노테이션 제거 Service 클래스에는 보통 @Service를 붙입니다. 이 어노테이션을 붙이면 Spring이 자동으로 Bean으로 등록해 줍니다. 그런데 하나의 인터페이스에 @Service가 붙은 클래스가 둘 이상 있으면, Spring은 어떤 구현을 써야 할지 결정할 수 없습니다. 그래서 여기서는 @Service를 직접 붙이지 않는 방향으로 갑니다.
YAML 만들기 YAML 설정은 단순합니다. 이번에는 boolean 값을 이용해 true일 때는 테스트 모드(SomeTestServiceImpl 사용), false일 때는 일반 모드(SomeServiceImpl 사용)로 동작하게 해 보겠습니다.
settings: TestMode: true 이 설정을 application.yml에 직접 넣어도 되고, 별도 파일로 분리해도 됩니다. 별도 파일을 쓸 경우에는 application.yml에서 해당 파일을 포함하도록 설정하는 것을 잊지 않으면 됩니다.
spring: profile: include: settings # 파일명이 application-settings.yml인 경우 Configuration 설정 어노테이션을 제거하면 ServiceImpl은 자동으로 Bean 등록되지 않습니다. 그렇다고 원하는 구현 클래스를 직접 선택하지 않을 수는 없습니다. 결국 상황에 맞는 구현을 골라 Bean으로 등록해 주는 설정 클래스가 필요합니다. 동시에 YAML 설정도 읽어야 하므로, 이를 @Configuration 클래스로 묶어 처리하면 됩니다.
@Configuration public class SomeServiceConfig { // YAML에 설정한 값을 읽는다 @Value(&#34;${settings.TestMode:false}&#34;) private boolean testMode; // YAML 설정에 따라 어떤 Impl을 Bean으로 등록할지 결정한다 @Bean public SomeService someService(SomeRepository repository, SomeTestRepository testRepository) { return this.testMode ? new SomeTestSerivce(testRepository) : new SomeServiceImple(repository); } } Spring에서는 @Value나 @ConfigurationProperties로 YAML 값을 읽을 수 있습니다. @ConfigurationProperties는 클래스 전체 필드에 값을 매핑할 때 유용하지만, 여기서는 boolean 하나만 읽으면 되므로 필드 단위로 쓰기 쉬운 @Value를 사용합니다. YAML 파일이 없을 때를 대비해 기본값으로 false도 지정해 두었습니다.
@Bean으로 등록할 때는 단순히 새 인스턴스를 만들어 반환하면 됩니다. 여기서는 구현 클래스가 의존하는 Repository도 함께 필요하므로, 메서드 인자로 받아 Bean으로 주입받습니다. 메서드 인자에 Repository 타입을 적어 두면 Spring이 자동으로 해당 Bean을 넣어 줍니다. 이후에는 테스트 모드인지 일반 모드인지에 따라 적절한 구현체를 반환하면 됩니다.
@Profile을 쓰는 경우 Bean을 상황별로 바꾸는 데는 @Profile을 쓰는 방법도 있습니다. 이 방식도 어렵지 않습니다. 먼저 YAML을 다음처럼 정의했다고 해 봅시다.
spring: profile: active: dev 이후에는 어떤 프로필에서 어떤 Bean을 사용할지 어노테이션으로 지정하면 됩니다.
@Configuration public class SomeServiceConfig { // dev나 debug일 때 등록할 Bean @Bean @Profile({&#34;dev&#34;, &#34;debug&#34;}) public SomeService someService(SomeTestRepository testRepository) { return new SomeTestSerivce(testRepository); } // prod일 때 등록할 Bean @Bean @Profile(&#34;prod&#34;) public SomeService someService(SomeRepository repository) { return new SomeServiceImple(repository); } } @Profile은 배열로 여러 프로필을 지정할 수 있어서, YAML 설정에 따라 어떤 Bean을 등록할지 비교적 간단하게 바꿀 수 있습니다. 두 방식 모두 쓸 수 있으니, 상황에 맞는 쪽을 고르면 됩니다.
마지막으로 요즘은 Django나 Express처럼 다른 언어의 웹 프레임워크도 더 접해 보고 싶지만, 아직은 Spring에서 배울 것이 훨씬 더 많습니다. 기능을 하나씩 알아 갈수록, 다른 프레임워크가 많아도 Spring이 엔터프라이즈 시장에서 오래 살아남은 이유는 결국 &ldquo;할 수 있는 일이 많다&quot;는 데 있다는 생각이 듭니다. 당분간은 Spring만으로도 충분히 더 쓸 이야기가 나올 것 같습니다.

Spring의 대표적인 특징을 하나 꼽자면 역시 @Autowired를 통한 DI1라고 생각합니다. 처음 Spring을 접했을 때는 new 없이 객체가 돌아가는 모습이 꽤 신기했습니다. 나중에 이것이 디자인 패턴의 한 형태라는 걸 알고 나서는 더 놀랐습니다. 좋은 코드를 쓰려면 여러 방향의 고민이 필요하다는 걸 다시 느꼈습니다.
그런데 Spring Boot를 쓰면서 한 가지 궁금한 점이 생겼습니다. 예전에는 @Autowired를 필드에 붙이는 것이 익숙했는데, 최근 프로젝트에서는 생성자에 붙이는 경우가 더 많았습니다. 왜 어떤 곳은 필드에 붙이고, 어떤 곳은 생성자에 붙이는지 궁금했고, 결국 모든 주입을 생성자로 바꾸기 전에 차이를 다시 정리해 보기로 했습니다.
결론부터 말하면, 대부분의 경우 @Autowired는 필드보다 생성자에 붙이는 편이 낫다고 합니다. 그리고 @Autowired를 필드나 생성자에 붙이는 방식은 각각 Field Injection과 Constructor Injection이라고 부릅니다. 이제 코드로 보겠습니다.
Field Injection 먼저 주입을 위해 다음과 같은 설정 클래스를 정의했다고 가정해 봅시다.
@Configuration public class MapperConfig { @Bean public ModelMapper mapper() { return new ModelMapper(); } } 여기서는 ModelMapper를 사용하겠습니다. ModelMapper는 이름이 같은 Getter/Setter를 기준으로 Bean 사이를 자동 매핑해 주는 라이브러리입니다.
이렇게 Bean을 등록한 뒤 @Autowired를 필드에 붙이는 서비스 클래스는 다음과 같습니다. 이것이 Field Injection입니다.
@Service public class ItemServiceImpl implements ItemService { @Autowired private ModelMapper mapper; } 저도 Spring을 처음 배울 때는 이런 필드 주입이 일반적이었습니다. 하지만 필드 주입에는 치명적인 문제가 있습니다. 필드가 null이어도 프로그램이 일단 실행된다는 점입니다. 클래스가 정상 동작하는 데 필요한 조건이 충족되지 않았는데도 실행되어 버리면 버그를 만들기 쉽습니다. 그래서 필드 주입은 좋지 않습니다.
Setter Injection 사실 주입은 Setter를 통해서도 가능합니다. 아주 일반적이진 않지만, 이를 Setter Injection이라고 부릅니다.
@Service public class ItemServiceImpl implements ItemService { private ModelMapper mapper; @Autowired public void setMapper(ModelMapper mapper) { this.mapper = mapper; } } Setter 주입의 문제는 필드 주입과 비슷합니다. 필요한 객체가 실제로 주입되었는지와 무관하게 프로그램이 실행될 수 있습니다. 이 문제를 막아 주는 방식이 다음에 나오는 생성자 주입입니다.
Constructor Injection 생성자를 통한 주입은 Constructor Injection이라고 하며, 코드는 다음과 같습니다.
@Service public class ItemServiceImpl implements ItemService { private final ModelMapper mapper; @Autowired public ItemServiceImpl(ModelMapper mapper) { this.mapper = mapper; } } 생성자 주입의 장점은 앞서 말한 문제를 비교적 일찍 드러낸다는 점입니다. 이건 Spring보다는 Java 언어 차원의 이야기이기도 한데, 생성자 인자를 만족하지 못하면 애초에 인스턴스를 만들 수 없습니다. 따라서 필요한 의존성이 빠진 상태로 객체가 만들어질 가능성을 줄일 수 있습니다.
또한 생성자 주입은 순환 참조2를 미리 막는 데도 도움이 됩니다. 필드 주입이나 Setter 주입은 실제 코드가 호출되기 전까지 문제를 파악하기 어렵지만, 생성자 주입은 순환 참조가 있으면 애플리케이션 시작 시점에 경고가 뜹니다.
필드 주입은 단위 테스트하기도 불편합니다. @Autowired가 붙은 필드에 직접 객체를 넣을 방법이 마땅치 않기 때문입니다. Setter를 쓰면 주입 자체는 가능하지만, 굳이 Setter를 쓸 이유도 크지 않습니다.
생성자 주입이 좋은 또 다른 이유는 필드를 final로 둘 수 있다는 점입니다. 필드가 클래스 안에서 바뀌지 않도록 보장할 수 있으니 더 안전합니다.
마지막으로 저도 예전에는 필드 주입을 별 생각 없이 썼습니다. 하지만 단위 테스트나 의존성 명시성 같은 문제를 알고 나서는 가능한 한 생성자 주입으로 정리하고 있습니다. IntelliJ도 생성자 주입을 권장하고, Spring 공식 문서도 같은 방향을 이야기하니 지금은 이유가 꽤 분명하다고 느낍니다.
Java 코딩 관점에서도 생성자는 중요합니다. Java에서는 따로 적지 않으면 인자 없는 생성자가 암묵적으로 생기기 때문에, 생성 시점에 필요한 값을 강제하고 싶다면 생성자를 명시적으로 작성해야 합니다. 이런 점까지 생각하면 생성자 주입이 단순히 Spring 스타일의 차이가 아니라, 객체를 더 분명하게 설계하는 방법이라는 점도 이해할 수 있습니다.
Dependency Injection(의존성 주입). 자세한 설명은 많으니 여기서는 생략하겠습니다. 간단히 말하면 객체를 외부에서 만들어 코드에 주입해, 코드와 의존성을 분리하는 방식입니다.&#160;&#x21a9;&#xfe0e;
순환 참조란 여러 객체가 서로를 참조하는 상황을 말합니다. 예를 들어 A를 만들 때 B가 필요하고, B를 만들 때 다시 A가 필요하면 서로를 끝없이 찾게 되어 무한 루프에 빠질 수 있습니다.&#160;&#x21a9;&#xfe0e;

Java의 Enum은 생각보다 활용 범위가 넓습니다. 읽기 쉽고, 상수 하나에 여러 값을 붙일 수 있다는 점도 편리합니다. 여러 클래스에서 공통 코드값을 다루거나 DB와 연동할 때 특히 유용해서, 저도 업무에서 자주 쓰고 있습니다. 단순히 상수를 모아 두는 데서 끝나지 않고, 필요한 처리까지 함께 담을 수 있다는 점도 장점입니다.
이번 글에서는 제가 경험하고 조사한 내용을 바탕으로 Java Enum의 활용법과 장점을 정리해 보겠습니다.
읽기 쉬움 코드가 읽기 쉽다는 건 결국 유지보수에 유리하다는 뜻입니다. 개인적으로는 프로그래밍이 일단 동작하게 만들기에서 끝나면 안 되고, 중복 처리를 메서드나 클래스로 분리하기, 남이 봐도 이해하기 쉬운 코드로 다듬기까지 가야 한다고 생각합니다.
테이블에 코드값이 있다고 해 봅시다. DB 종류에 따라 boolean일 수도 있고 char(1)일 수도 있습니다. 코드값이 단순히 두 상태만 가지는 것이 아니라 세 개 이상일 수도 있습니다. Java 내부 상태를 String으로 두고 DB에는 char(1)로 저장하는 예를 들면, 대략 이런 코드가 필요합니다.
// String으로 표현된 상태를 DB 코드값으로 바꾸는 메서드 예시 public String toCodeValue(String status) { if (status.equals(&#34;TRUE&#34;)) { return &#34;0&#34;; } else { return &#34;1&#34;; } } 이 메서드를 쓰는 코드는 아래처럼 됩니다.
// item 객체에 상태 지정 public void setStatusTrue(Item item) { item.setStatus(&#34;TRUE&#34;); } 하드코딩된 status는 상수로 바꿀 수 있습니다. 하지만 상수를 일반 클래스에 두면 그 값이 어디에 정의돼 있는지 먼저 알아야 합니다. 어디에 있는지 모르면 수정하기도 어렵고, 같은 상수를 여러 클래스에 중복해서 만들 가능성도 있습니다.
게다가 이런 코드에서는 결과를 보기 전까지 상태가 어떻게 바뀌는지 확인하기 어렵습니다. 만약 TRUE도 FALSE도 아닌 제3의 문자열이 들어온다면 if 분기를 계속 늘려야 합니다.
이걸 Enum으로 바꾸면 아래처럼 됩니다.
public enum StatusEnum { TRUE(&#34;0&#34;), FALSE(&#34;1&#34;); private Integer codeValue; StatusEnum(Integer codeValue) { this.codeValue = codeValue; } public Integer getCodeValue() { return codeValue; } } 상수명과 코드값을 붙이고 필드, 생성자, Getter만 두면 됩니다. 이런 Enum은 Lombok으로도 쉽게 만들 수 있습니다.
@Getter @AllArgsConstructor public enum StatusEnum { TRUE(&#34;0&#34;), FALSE(&#34;1&#34;); private Integer codeValue; } 실제로 쓰면 이렇게 됩니다.
Item item = new Item(); item.setStatus(StatusEnum.TRUE.getCodeValue()); // &#34;0&#34; Enum을 쓰면 넣을 값이 명확해집니다. 독립된 클래스이므로 패키지로 분리해 관리하기도 쉽습니다. 나중에 코드값이 늘어나도 Enum만 수정하면 됩니다. 아예 필드 자체를 Enum으로 둘 수도 있습니다.
@Data public class Item { private StatusEnum status; } 필드가 Enum이면 값 지정이 더 간단합니다.
Item item = new Item(); item.setStatus(StatusEnum.TRUE); // TRUE로 저장 String itemCodeValue = item.getStatus().getCodeValue(); 여러 값 보관 Enum의 장점은 상수 하나에 여러 값을 붙일 수 있다는 점입니다. 예를 들어 두 개 이상의 DB를 쓰고 있고, 같은 항목을 한쪽은 char(1), 다른 쪽은 boolean으로 관리한다면 둘 다 하나의 Enum으로 묶을 수 있습니다.
@Getter @AllArgsConstructor public enum MultiValueEnum { Y(&#34;0&#34;, true), N(&#34;1&#34;, false); private Integer charValue; private boolean booleanValue; } 어떤 Getter를 쓰느냐에 따라 같은 상수라도 다른 타입의 값을 돌려줍니다.
Item item = new Item(); item.setStatus(MultiValueEnum.Y.getCharValue()); // &#34;0&#34; item.setStatus(MultiValueEnum.Y.getBooleanValue()); // true 배열이나 List로도 처리할 수 있지 않느냐고 할 수 있습니다. 물론 가능합니다. Stream을 쓰면 List를 값으로 들고 있다가 그 안의 값과 비교하는 방식도 만들 수 있습니다.
@Getter @AllArgsConstructor public enum ListValueEnum { Y(Arrays.asList(&#34;Good&#34;, &#34;Excellent&#34;)), N(Arrays.asList(&#34;Bad&#34;, &#34;Unavailable&#34;)), NULL(null); private List&lt;String&gt; codeValueList; public boolean hasCodeValue(String codeValue) { return codeValueList.stream().anyMatch(code -&gt; code.equals(codeValue)); } public ListValueEnum findByValue(String codeValue) { return Arrays.stream(ListValueEnum.values()) .filter(listValueEnum -&gt; listValueEnum.hasCodeValue(codeValue)) .findAny() .orElse(NULL); } } 저도 처음 봤을 때는 조금 낯설었지만, 상황에 따라 충분히 써 볼 만한 방식입니다.
필드로 쓰는 Enum에 별도 값이 없다면 아래처럼 어노테이션만 붙여도 됩니다.
@Data public class Item { @Enumerated(EnumType.STRING) private StringEnum codeValue1; } 클래스처럼 쓰기 Enum은 클래스이기 때문에 처리 로직도 함께 넣을 수 있습니다. 메서드를 값처럼 들고 있는 형태라고 보면 됩니다. 이 부분은 이전에 Lambda를 다룬 글을 함께 보면 이해가 더 쉽습니다.
@AllArgsConstructor public enum CalculateEnum { TYPE_1(num -&gt; num), TYPE_2(num -&gt; num + 10); private Function&lt;Integer, Integer&gt; calculate; public Integer calculate(Integer number) { return calculate.apply(number); } } 사용하면 이런 식입니다.
Integer type_1 = CalculateEnum.TYPE_1.calculate(10); // 10 Integer type_2 = CalculateEnum.TYPE_2.calculate(10); // 20 마지막으로 공통 부품을 중복해서 만들면 관리도 어렵고, 코드도 불필요하게 늘어납니다. Enum은 이런 문제를 줄이는 데 꽤 효과적입니다.
다만 모든 정수를 꼭 Enum으로 바꿔야 하는 것은 아닙니다. 경우에 따라 테이블로 관리하는 편이 더 나을 수도 있고, 특정 클래스 안에서만 쓰는 값이라면 굳이 Enum을 만들 필요도 없습니다.
그래도 이런 활용법을 알고 있으면 나중에 분명 쓸 일이 생깁니다. 저도 처음에는 Lambda를 그저 읽기 어려운 문법 정도로만 생각했지만, Function과 함께 쓰는 방식을 이해하고 나서는 훨씬 적극적으로 활용하게 됐습니다. 결국 중요한 건 도구를 많이 아는 것보다, 어떤 상황에서 무엇을 쓰면 좋은지 판단할 수 있는 경험이라고 생각합니다.

이전 글에서 Builder 패턴과 함께 Lombok을 소개했습니다. Bean은 물론 immutable 클래스1나 Builder도 쉽게 만들 수 있고, 어노테이션만으로 다양한 옵션을 붙일 수 있어서 꽤 편리합니다. 그런데 이번에는 Lombok을 쓰다가 버그처럼 보이는 현상을 발견해서 기록해 둡니다.
버그가 생긴 곳 어디서 문제가 생겼는지 설명하기 전에, 먼저 어떤 Lombok 어노테이션을 조합해서 썼는지 정리하겠습니다. 저와 비슷한 조합으로 쓰는 분이라면 같은 현상을 겪을 수도 있기 때문입니다.
Lombok의 @Builder에는 toBuilder=true 옵션이 있습니다. 이 옵션을 쓰면 새 인스턴스를 만들 때 static 메서드를 사용하고, 이미 존재하는 인스턴스에서 일부 값만 바꿔 다시 만들 수 있습니다.
// @Builder만 사용해 새 인스턴스 생성 House house2 = House.builder().type(&#34;wooden&#34;).build(); // toBuilder로 기존 인스턴스에서 일부 값만 바꿔 재생성 House house3 = house2.toBuilder().type(&#34;block&#34;).build(); 또 Builder를 쓰면서도 기본값으로 유지하고 싶은 필드가 있습니다. 제 경우는 List였습니다. 인스턴스를 만들 때 List를 초기화해 두고, Builder로 통째로 넣거나 addCard() 같은 메서드로 하나씩 추가하고 싶었습니다.
이를 위해 @Builder.Default로 필드를 초기화하고, Builder 클래스에 커스텀 메서드를 붙였습니다.
@Builder(toBuilder = true) public class Wallet { // Builder로 생성될 때도 null이 되지 않게 한다 @Builder.Default List&lt;String&gt; cards = new ArrayList&lt;&gt;(); // Builder에 커스텀 메서드를 추가 public class WalletBuilder { public WalletBuilder addCard(String card) { this.cards.add(card); return this; } } } 이렇게 하면 아래처럼 동작하길 기대했습니다.
// 인스턴스를 만들면서 List에 추가 Wallet myWallet = Wallet.builder().addCard(&#34;Apple Card&#34;).build(); // 기존 인스턴스에 추가 Wallet newWallet = myWallet.toBuilder().addCard(&#34;American Express Card&#34;).build(); 그런데 실제로 테스트해 보니 이 조합에서 문제가 생겼습니다.
어떤 버그였나 기존 인스턴스에서는 add가 잘 됐지만, 인스턴스를 생성하면서 바로 add하면 NPE2가 발생했습니다. 확인해 보니 this.cards.add(card);에서 예외가 났고, 생성되지 않은 객체에 요소를 추가하려 한 것이었습니다. 즉, List가 제대로 초기화되지 않았던 것입니다.
조금 찾아보니 비슷한 이슈가 있었습니다. 2017년에 올라온 글이라 꽤 오래된 문제처럼 보였지만, 지금 겪는 현상과 거의 같았습니다. 게다가 Lombok 1.18.2에서 해결됐다는 이야기도 있었는데, 제가 쓰던 버전은 1.18.8이었습니다. 해결된 줄 알았는데 다시 생긴 것인지, 버전업 과정에서 재발한 것인지 모르겠지만 같은 현상이 반복됐습니다.
해결 방법 제가 찾은 해결책은 toBuilder=true와 @Builder.Default를 둘 다 쓰지 않는 것이었습니다. Builder에 필드가 제대로 전달되지 않는다면 @Builder.Default는 의미가 없고, toBuilder도 직접 메서드를 작성해 버리면 됩니다.
// toBuilder 옵션을 쓰지 않는다 @Builder public class Wallet { // @Builder.Default도 쓰지 않는다 List&lt;String&gt; cards = new ArrayList&lt;&gt;(); // toBuilder도 직접 작성한다 public WalletBuilder toBuilder() { return new WalletBuilder().cards(this.cards); } } 이제는 인스턴스를 만들 때도 List가 제대로 초기화된 상태로 전달됐습니다. 결국 어노테이션을 과하게 믿지 말아야 한다는 뜻이기도 합니다.
배운 점 라이브러리를 써서 코드 양을 줄이고 자동화하는 것은 생산성을 높이는 좋은 방법입니다. 다만 사람이 쓴 코드든 라이브러리가 생성한 코드든, 어디에서 문제가 생길지는 항상 열어 두어야 합니다. 때로는 조금 번거롭더라도 명시적인 코드가 더 안전합니다.
이번 일은 어노테이션만 믿고 끝까지 우회하려 했다면 원인을 더 늦게 찾았을 수도 있는 사례였습니다. 그런 의미에서, 자동 생성 코드를 어디까지 신뢰할지 다시 생각해 보게 된 계기였습니다.
같은 방식으로 구현할 생각이 있다면 이런 문제도 생길 수 있다는 정도로 참고하면 좋겠습니다. 편리한 라이브러리일수록 내부 동작을 너무 당연하게 믿지 않는 편이 낫다는 걸 다시 느꼈습니다.
한 번 생성하면 중간에 값을 바꿀 수 없는 클래스입니다. String이 대표적입니다.&#160;&#x21a9;&#xfe0e;
NullPointerException입니다. 참조하려는 객체가 메모리에 없을 때 발생하는, Java에서 가장 자주 마주치는 예외 중 하나입니다.&#160;&#x21a9;&#xfe0e;
